const data = $items("OHLC").map(item => ({
  time: item.json[0],
  open: parseFloat(item.json[1]),
  high: parseFloat(item.json[2]),
  low: parseFloat(item.json[3]),
  close: parseFloat(item.json[4]),
  volume: parseFloat(item.json[5])
}));

const length = 5; 
const mitigationMethod = 'Wick'; 

let bullishOB = [];
let bearishOB = [];
let os = 0; 

for (let i = 0; i < data.length; i++) {

if (i >= length) {
  const prevHigh = Math.max(...data.slice(i - length, i).map(d => d.high));
  const prevLow  = Math.min(...data.slice(i - length, i).map(d => d.low));

  const currentClose = data[i].close;
  if (currentClose > prevHigh) {
    os = 1;
  }
  else if (currentClose < prevLow) {
    os = 0;
  }
}
  if (i >= length * 2) {
    const pIdx = i - length; 
    const targetVol = data[pIdx].volume;

    const leftVol = data.slice(pIdx - length, pIdx).map(d => d.volume);
    const rightVol = data.slice(pIdx + 1, pIdx + length + 1).map(d => d.volume);

    const isPHV = targetVol > Math.max(...leftVol) && targetVol >= Math.max(...rightVol);

    if (isPHV) {
      const targetCandle = data[pIdx];
      const hl2 = (targetCandle.high + targetCandle.low) / 2;

      if (os === 1) {
        bullishOB.unshift({
          time: targetCandle.time,
          top: hl2, 
          bottom: targetCandle.low, 
          avg: (hl2 + targetCandle.low) / 2, 
          mitigated: false
        });
      } 
      // Bearish OB: os == 0 
      else if (os === 0) {
        bearishOB.unshift({
          time: targetCandle.time,
          top: targetCandle.high, 
          bottom: hl2,  
          avg: (targetCandle.high + hl2) / 2, 
          mitigated: false
        });
      }
    }
  }

  const currentBar = data[i];

  const bullPrice = mitigationMethod === 'Close' ? currentBar.close : currentBar.low;
  const bearPrice = mitigationMethod === 'Close' ? currentBar.close : currentBar.high;

  bullishOB = bullishOB.filter(ob => !(bullPrice < ob.bottom));

  bearishOB = bearishOB.filter(ob => !(bearPrice > ob.top));
}

return [{
  symbol: $('Loop Over Items').first().json.Pair,
  timeframe: "1H",
  totalCandles: data.length,
  bullishOB: bullishOB.slice(0, 10),
  bearishOB: bearishOB.slice(0, 10),
  lastPrice: data[data.length - 1].close
}];

