const data = $items("OHLC").map(item => ({
  time: Number(item.json[0]),
  open: parseFloat(item.json[1]),
  high: parseFloat(item.json[2]),
  low: parseFloat(item.json[3]),
  close: parseFloat(item.json[4])
}));

const obRows = $items('ob-history');
if (!data.length || !obRows.length) return [{ json: { error: "Data missing" } }];

const latestRow = obRows[obRows.length - 1].json;
const ob = { time: Number(latestRow.time), type: String(latestRow.type).toLowerCase() };
const obIndex = data.findIndex(c => Math.abs(c.time - ob.time) < 1000);

const after = data.slice(obIndex + 1);
let B = null, C = null, indexB = 0;

if (ob.type === "bearish") {
  let lowest = after[0].low;
  for (let i = 0; i < after.length; i++) {
    if (after[i].low < lowest) { lowest = after[i].low; indexB = i; }
  }
  B = lowest;
  const afterB = after.slice(indexB + 1);
  if (afterB.length) {
    let highestC = afterB[0].high;
    for (let i = 0; i < afterB.length; i++) {
      if (afterB[i].high > highestC) highestC = afterB[i].high;
    }
    C = highestC;
  }
} else {
  let highest = after[0].high;
  for (let i = 0; i < after.length; i++) {
    if (after[i].high > highest) { highest = after[i].high; indexB = i; }
  }
  B = highest;
  const afterB = after.slice(indexB + 1);
  if (afterB.length) {
    let lowestC = afterB[0].low;
    for (let i = 0; i < afterB.length; i++) {
      if (afterB[i].low < lowestC) lowestC = afterB[i].low;
    }
    C = lowestC;
  }
}
if (C === null) C = (ob.type === "bearish") ? after[after.length - 1].high : after[after.length - 1].low;

let A = null;
const before = data.slice(Math.max(0, obIndex - 500), obIndex);

if (ob.type === "bearish") {
  for (let i = before.length - 6; i > 5; i--) {
    const currentHigh = before[i].high;
    const isMajorPeak = before.slice(i - 5, i + 6).every(d => currentHigh >= d.high);

    if (isMajorPeak && currentHigh > C) {
      A = currentHigh;
      break; 
    }
  }
  if (!A) {
    const proximalRange = before.slice(-100);
    A = Math.max(...proximalRange.map(d => d.high));
  }
} else {
  for (let i = before.length - 6; i > 5; i--) {
    const currentLow = before[i].low;
    const isMajorValley = before.slice(i - 5, i + 6).every(d => currentLow <= d.low);

    if (isMajorValley && currentLow < C) {
      A = currentLow;
      break;
    }
  }
  if (!A) {
    const proximalRange = before.slice(-100);
    A = Math.min(...proximalRange.map(d => d.low));
  }
}

const AB = Math.abs(B - A);
const BC = Math.abs(C - B);
const retracement = AB > 0 ? BC / AB : 0;

let classification = retracement <= 0.7 ? "middle" : "beginning";
let fiboLevel = classification === "beginning" ? 1.0 : 0.786;

let structureValid = (ob.type === "bearish") ? (A > C && C > B) : (A < C && C < B);

return [{
  json: {
    symbol: latestRow.symbol || "BTCUSDT",
    type: ob.type,
    structureValid,
    classification,
    retracement: Number(retracement.toFixed(3)),
    fiboLevel,
    A: Number(A.toFixed(1)),
    B: Number(B.toFixed(1)),
    C: Number(C.toFixed(1)),
    tp: Number((ob.type === "bearish" ? C - (AB * fiboLevel) : C + (AB * fiboLevel)).toFixed(1))
  }
}];

