const lastPrice = $('set-new-sl').first().json.lastPrice;
const newSL = $('set-new-sl').first().json.newSL;
const positionSide = $('check-position').first().json.side;

let slValidation = false;

if (!isNaN(lastPrice) && !isNaN(newSL)) {

