const items = $("OHLC").all();
const obNode = $('get-latest-OB').first().json;
const ob = obNode.latestOB;
const lastPrice = obNode.lastPrice;

const candles = items.map(c => ({
  time: Number(c.json[0]),
  open: parseFloat(c.json[1]),
  high: parseFloat(c.json[2]),
  low: parseFloat(c.json[3]),
  close: parseFloat(c.json[4]),
  volume: parseFloat(c.json[5])
}));

if (candles.length < 50) return [{ json: { error: "Need more candles" } }];

const n = candles.length;
const c1 = candles[n - 1]; 
const c2 = candles[n - 2]; 
const c3 = candles[n - 3];

const calculateYZVol = (data, period = 24) => {
    const subset = data.slice(-period);
    const log = (val) => Math.log(val);
    let s_o = 0, s_c = 0, s_rs = 0;
    for (let i = 1; i < subset.length; i++) {
        s_o += Math.pow(log(subset[i].open / subset[i-1].close), 2);
        s_c += Math.pow(log(subset[i].close / subset[i].open), 2);
        s_rs += log(subset[i].high/subset[i].close) * log(subset[i].high/subset[i].open) +
                log(subset[i].low/subset[i].close) * log(subset[i].low/subset[i].open);
    }
    const k = 0.34 / (1.34 + (period + 1) / (period - 1));
    return Math.sqrt((s_o / period) + k * (s_c / period) + (1 - k) * (s_rs / period));
};

const yzVol = calculateYZVol(candles);
const priceShock = Math.abs(c2.close - c2.open) / (c2.open * yzVol);

function EMA(data, period) {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  for (let i = 1; i < data.length; i++) {
    ema = data[i].close * k + ema * (1 - k);
  }
  return ema;
}

const ema20 = EMA(candles, 20);
const ema50 = EMA(candles, 50);
const isTrending = Math.abs(ema20 - ema50) / ema50 > 0.001; 

let score = 0;
const isBullish = ob.type.toLowerCase() === 'bullish';

let tScore = 0;
const hasSweep = isBullish ? (c2.low < ob.bottom) : (c2.high > ob.top);
const trendAligned = isBullish ? (c1.close > ema20) : (c1.close < ema20);

if (hasSweep) tScore = 1.0;
else if (!ob.mitigated && trendAligned) tScore = 0.8;
else tScore = 0.4;

let vScore = (priceShock > 0.5 && priceShock < 2.5) ? 1.0 : 0.5;

let dScore = (priceShock > 1.2) ? 1.0 : 0.6;

const avgVol = candles.slice(-20).reduce((a,b) => a + b.volume, 0) / 20;
const volRatio = c1.volume / avgVol;
let lScore = (volRatio > 1.5) ? 1.0 : (volRatio > 1.0 ? 0.7 : 0.4);

const finalScore = (tScore * 30) + (vScore * 20) + (dScore * 30) + (lScore * 20);

const entryPrice = ob.avg;
const stopLoss = isBullish ? ob.bottom : ob.top;
const isFresh = !ob.mitigated;

let decision = "NO TRADE";
const distanceToEntry = Math.abs(lastPrice - entryPrice) / lastPrice;
const minGap = yzVol * 0.15; 

if (finalScore >= 60 && isFresh && distanceToEntry > minGap) {
    if (isBullish && lastPrice > entryPrice) decision = "LIMIT";
    if (!isBullish && lastPrice < entryPrice) decision = "LIMIT";
}

return [{
  json: {
    decision: decision,
    confidence: finalScore.toFixed(2),
    market_regime: {
      volatility: yzVol.toFixed(5),
      price_shock: priceShock.toFixed(2),
      is_trending: isTrending,
      volume_ratio: volRatio.toFixed(2)
    },
    execution_params: {
      side: isBullish ? "BUY" : "SELL",
      entry: entryPrice,
      sl: stopLoss,
      tp: isBullish 
          ? parseFloat((entryPrice + (entryPrice - stopLoss) * 2.5).toFixed(2))
          : parseFloat((entryPrice - (stopLoss - entryPrice) * 2.5).toFixed(2))
    },
    structure_check: {
      liquidity_sweep: hasSweep,
      is_mitigated: ob.mitigated
    }
  }
}];

